inputs.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const query = cleanArg(arg0);
const rawMode = cleanArg(arg1).toLowerCase();
const mode = ['top','accounts','hashtags','places'].includes(rawMode) ? rawMode : 'top';
const maxResults = Math.max(1, Math.min(50, Number(cleanArg(arg2)) || 20));
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\s+/g, ' ').trim();
const isVisible = (node) => {
  if (!(node instanceof Element)) return false;
  const rect = node.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) return false;
  const style = window.getComputedStyle(node);
  return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
};
if (!query) throw new Error('query is required');
const searchTrigger = Array.from(document.querySelectorAll('a,button,[role="button"],[role="link"]')).filter(isVisible).find((node) => /search/i.test(normalize(node.getAttribute('aria-label') || '') + ' ' + normalize(node.textContent || '')));
if (!searchTrigger) throw new Error('Search nav entry not found — is the user signed in?');
searchTrigger.click();
await sleep(1500);
const input = document.querySelector("input[aria-label='Search input'], input[placeholder='Search']");
if (!(input instanceof HTMLInputElement)) return { query, mode, input_accepted: false, results_ready: false, total_results: 0, results: [] };
input.focus();
const valueSetter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value').set;
valueSetter.call(input, '');
input.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: null, inputType: 'deleteContentBackward' }));
await sleep(150);
let typed = '';
for (const ch of query) {
  typed += ch;
  input.dispatchEvent(new KeyboardEvent('keydown', { key: ch, bubbles: true }));
  valueSetter.call(input, typed);
  input.dispatchEvent(new InputEvent('input', { bubbles: true, composed: true, data: ch, inputType: 'insertText' }));
  input.dispatchEvent(new KeyboardEvent('keyup', { key: ch, bubbles: true }));
  await sleep(90);
}
await sleep(2200);
const classifyHref = (href) => {
  if (!href) return null;
  const trimmed = href.replace(/[?#].*$/, '');
  const tagMatch = trimmed.match(/^\/explore\/tags\/([^/]+)\/?$/i);
  if (tagMatch) return { kind: 'hashtag', tag: tagMatch[1].toLowerCase(), target: trimmed };
  const placeMatch = trimmed.match(/^\/explore\/locations\/([^/]+)(?:\/([^/]+))?\/?$/i);
  if (placeMatch) return { kind: 'place', place_slug: [placeMatch[1], placeMatch[2]].filter(Boolean).join('/'), target: trimmed };
  const profileMatch = trimmed.match(/^\/([a-z0-9._]+)\/?$/i);
  if (profileMatch && !/^(explore|reels|direct|accounts|stories|p|reel|tv)$/i.test(profileMatch[1])) {
    return { kind: 'account', handle: profileMatch[1].toLowerCase(), target: trimmed };
  }
  return null;
};
const anchors = Array.from(document.querySelectorAll('a[href]')).filter(isVisible);
const byHref = new Map();
let position = 0;
for (const anchor of anchors) {
  const href = anchor.getAttribute('href') || '';
  const classified = classifyHref(href);
  if (!classified) continue;
  if (byHref.has(classified.target)) continue;
  const container = anchor.closest('div[role="button"], div') || anchor;
  const rawText = normalize(anchor.textContent || container.textContent || '');
  if (!rawText) continue;
  position += 1;
  const lines = (container.innerText || anchor.innerText || '').split('\n').map(normalize).filter(Boolean);
  const displayName = lines.find((line) => line && !/^verified$|followed by/i.test(line) && line !== classified.handle && line !== classified.tag) || '';
  byHref.set(classified.target, {
    ...classified,
    display_name: displayName,
    full_text: rawText.slice(0, 200),
    result_url: new URL(classified.target, window.location.origin).toString(),
    position
  });
}
const allResults = Array.from(byHref.values());
const filtered = mode === 'top' ? allResults : allResults.filter((row) => row.kind === ({ accounts: 'account', hashtags: 'hashtag', places: 'place' })[mode]);
return {
  query,
  mode,
  input_accepted: input.value === query,
  results_ready: filtered.length > 0 || allResults.length > 0,
  total_results: filtered.length,
  results: filtered.slice(0, maxResults)
};
